module asyn_fifo #(
    parameter	WIDTH = 8,
    parameter 	DEPTH = 16,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output wire				wfull,
    output wire				rempty,
    output reg [WIDTH-1:0]	rdata
);

    reg [WIDTH-1:0] ram [DEPTH-1:0];
    reg [ADDR_WIDTH-1:0] waddr, raddr;
    wire [WIDTH-1:0] rdata_ram;

    always @(posedge wclk) begin
        if (winc && !wfull) begin
            ram[waddr] <= wdata;
            waddr <= waddr + 1'b1;
        end
    end

    always @(posedge rclk) begin
        if (rinc && !rempty) begin
            rdata <= ram[raddr];
            raddr <= raddr + 1'b1;
        end
    end

    reg [ADDR_WIDTH:0] wptr;
    wire [ADDR_WIDTH:0] wptr_gray, wptr_bin;
    wire [ADDR_WIDTH:0] wptr_next = wptr + {{ADDR_WIDTH{1'b0}}, 1'b1};

    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn)
            wptr <= {ADDR_WIDTH+1{1'b0}};
        else if (winc && !wfull)
            wptr <= wptr_next;
    end

    reg [ADDR_WIDTH:0] rptr;
    wire [ADDR_WIDTH:0] rptr_gray, rptr_bin;
    wire [ADDR_WIDTH:0] rptr_next = rptr + {{ADDR_WIDTH{1'b0}}, 1'b1};

    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn)
            rptr <= {ADDR_WIDTH+1{1'b0}};
        else if (rinc && !rempty)
            rptr <= rptr_next;
    end

    reg [ADDR_WIDTH:0] rptr_sync1, rptr_sync2;
    always @(posedge wclk) begin
        rptr_sync1 <= rptr;
        rptr_sync2 <= rptr_sync1;
    end

    reg [ADDR_WIDTH:0] wptr_sync1, wptr_sync2;
    always @(posedge rclk) begin
        wptr_sync1 <= wptr;
        wptr_sync2 <= wptr_sync1;
    end

    assign wfull = (wptr_sync2 == {~rptr[ADDR_WIDTH:ADDR_WIDTH-1], rptr[ADDR_WIDTH-2:0]});
    assign rempty = (wptr_sync2 == rptr_sync2);

endmodule

module dual_port_RAM #(parameter DEPTH = 16,  parameter WIDTH = 8)
(
	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule
